from typing import List

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x != root_y:
            if self.rank[root_x] > self.rank[root_y]:
                self.parent[root_y] = root_x
            elif self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1

class Solution:
    def findAllPeople(self, n: int, meetings: List[List[int]], firstPerson: int) -> List[int]:
        uf = UnionFind(n)
        uf.union(0, firstPerson)

        meetings.sort(key=lambda x: x[2])

        people_with_secret = set()
        i = 0
        while i < len(meetings):
            time = meetings[i][2]
            while i < len(meetings) and meetings[i][2] == time:
                x, y, _ = meetings[i]
                uf.union(x, y)
                i += 1
            people = set()
            stack = [0]
            while stack:
                person = stack.pop()
                if person not in people:
                    people.add(person)
                    root = uf.find(person)
                    for j in range(n):
                        if uf.find(j) == root:
                            stack.append(j)
            people_with_secret = people_with_secret.union(people)

        return list(people_with_secret)
